#!/usr/bin/perl

use CGI;

my $cgi = new CGI;

# Get the "next" parameter from the POST data
my $redirect_url = $cgi->param('next');

# Check if the parameter is present and if it's a valid URL 
# For simplicity, we will just check if it starts with http/https
if ($redirect_url && $redirect_url =~ /^https?:\/\//) {
    
    # Print the HTTP/1.1 Location header with provided URL
    print $cgi->header(-status => 302, -location => $redirect_url);

} else {
    
    # If no valid "next" parameter provided, redirect to a default location
    print $cgi->header(-status => 302, -location => 'https://www.default.com');

}